function getFilename(id, mode) {
  if(mode == 'EvalA-a'){
    return id2filenames[id] + ".png"
  } else {
    return "seed" + formatWithLeadingZeros(id, 4) + ".png"
  }
}

function sampleImages(){
  comparison = getRandomInt(1)

  if(comparison == 0) {
    num_renderings = 1000
    // Method order is randomized
    draping_modes = shuffleArray(["EvalA-a", "EvalA-b"])
  } else if(comparison == 1) {
    num_renderings = 1000
    draping_modes = shuffleArray(["EvalA-a", "EvalA-c"])
  }
  rendering_id = getRandomInt(num_renderings)

  // Display corresponding images
  base_url = "https://raw.githubusercontent.com/doub7e/doub7e.github.io/main/images/"
  img0.src = base_url + draping_modes[0] + "/" + getFilename(rendering_id, draping_modes[0])
  img1.src = base_url + draping_modes[1] + "/" + getFilename(rendering_id, draping_modes[1])
//   img0.src = "https://raw.githubusercontent.com/doub7e/doub7e.github.io/main/00267.png"
//   img1.src = "https://raw.githubusercontent.com/doub7e/doub7e.github.io/main/00235.png"
//   img0.src = base_url + draping_modes[0] + "/" + rendering_id + ".png"
//   img1.src = base_url + draping_modes[1] + "/" + rendering_id + ".png"

}

function greyOutImages(){
  greyOutImage(img0)
  greyOutImage(img1)
  greyOutImage(imgNone)
}

function greyOutImage(img){
  img.classList.add("desaturate")
  img.classList.remove("imgHover")
}

function UNgreyOutImages(){
  UNgreyOutImage(img0)
  UNgreyOutImage(img1)
  UNgreyOutImage(imgNone)
}

function UNgreyOutImage(img){
  img.classList.remove("desaturate")
  img.classList.add("imgHover")
}

function getLock(){
  img0.onclick = (event) => {}
  img1.onclick = (event) => {}
  imgNone.onclick = (event) => {}
  greyOutImages()
}

function releaseLock(){
  img0.onclick = (event) => {clickImage('0')}
  img1.onclick = (event) => {clickImage('1')}
  imgNone.onclick = (event) => {clickImage('none')}
  UNgreyOutImages()
}

function sendData(data) {
  const XHR = new XMLHttpRequest();
  const FD = new FormData();

  // Push our data into our FormData object
  for (const [name, value] of Object.entries(data)) {
    FD.append(name, value);
  }

  // Define what happens on successful data submission
  XHR.addEventListener('load', (event) => {
    console.log('Sucessfully sent response.');
  });

  // Define what happens in case of error
  XHR.addEventListener('error', (event) => {
    alert('Oops! Something went wrong. Try refreshing the page. If the issue persists, please read the message at the bottom of the page.');
  });

  // Set up our request
  XHR.open('POST', 'https://script.google.com/macros/s/AKfycbxoKasf-Cl2dgkz3amhgV5MxIzwsHxJD6ZkkYrzVr8ZVw6tyRsY8BoZnbPWj8xq0zD4/exec');

  // Send our FormData object; HTTP headers are set automatically
  XHR.send(FD);
}

function stringGen(len){
  var text = "";
  var possible = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
  for (var i = 0; i < len; i++)
    text += possible.charAt(getRandomInt(possible.length));
  return text;
}

function getCookie(cname) {
  let name = cname + "=";
  let decodedCookie = decodeURIComponent(document.cookie);
  let ca = decodedCookie.split(';');
  for(let i = 0; i <ca.length; i++) {
    let c = ca[i];
    while (c.charAt(0) == ' ') {
      c = c.substring(1);
    }
    if (c.indexOf(name) == 0) {
      return c.substring(name.length, c.length);
    }
  }
  return "";
}

function setCookie(cname, cvalue, exdays) {
  const d = new Date();
  d.setTime(d.getTime() + (exdays*24*60*60*1000));
  let expires = "expires="+ d.toUTCString();
  document.cookie = cname + "=" + cvalue + ";" + expires + ";path=/;SameSite=Strict";
}

function userIdSetup(){
  userId = getCookie("userId")
  if(userId == ""){
    userId = stringGen(10)
    setCookie("userId", userId, 100)
  }
  return userId
}
